import{c as t,S as o,j as n,m as r}from"./chunks/framework.D39xfXuw.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md","lastUpdated":1779719557000}'),a={name:"getting-started/index.md"};function i(s,e,l,d,c,g){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>ilingo</strong> is a small, framework-agnostic translation and internationalization library for TypeScript. It gives you four things and nothing more:</p><ol><li>An <strong>orchestrator</strong> (<code>Ilingo</code>) that resolves a key against a locale chain.</li><li>A <strong>port</strong> (<code>IStore</code>) with two stock adapters: in-memory and file-system.</li><li>A <strong>template</strong> engine for <code>{{var}}</code> substitution plus <code>Intl</code> formatters.</li><li>An optional <strong>typed-catalog</strong> mode that turns typos into compile errors.</li></ol><p>Everything else — pluralization, fallback chains, missing-key handling, framework adapters — composes from those four pieces.</p><h2 id="why-ilingo" tabindex="-1">Why ilingo? <a class="header-anchor" href="#why-ilingo" aria-label="Permalink to &quot;Why ilingo?&quot;">​</a></h2><ul><li><strong>Tiny.</strong> The core has two runtime dependencies. ESM-only, browser-safe, no <code>node:</code> imports in the core.</li><li><strong>Pluggable.</strong> A custom store is one class implementing three methods.</li><li><strong>Locale-first resolution.</strong> A <code>pt-BR</code> request walks <code>pt-BR → pt → en</code> before giving up — and the closest locale wins regardless of which store holds it.</li><li><strong>Standards-aligned.</strong> Plurals go through <code>Intl.PluralRules</code>. Formatters delegate to <code>Intl.NumberFormat</code>, <code>Intl.DateTimeFormat</code>, <code>Intl.ListFormat</code>.</li><li><strong>Type-safe when you want.</strong> Drop in <code>defineCatalog()</code> and the compiler enforces every group, key, and <code>count</code>.</li></ul><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><strong><a href="./installation">Installation</a></strong> — install the packages you need.</li><li><strong><a href="./quick-start">Quick Start</a></strong> — a 30-second example.</li><li><strong><a href="/guide/">Guide → Overview</a></strong> — the conceptual map.</li><li><strong><a href="/integrations/">Integrations</a></strong> — file system, Vue, Vuelidate.</li></ul>',8)])])}const p=t(a,[["render",i]]);export{u as __pageData,p as default};
